(function(){"use strict";function fadeOut(el,duration){duration=typeof duration==="number"?duration:400;const durationMs=duration>10?duration:duration*1e3;const durationSec=durationMs/1e3;el.style.display=el.style.display||"";gsap.to(el,{y:-20,opacity:0,duration:durationSec,onComplete:function(){el.style.display="none"}})}function setCookie(name,value,msExpiry){const d=new Date;const expiry=typeof msExpiry==="number"?msExpiry:2592e6;d.setTime(d.getTime()+expiry);const expires="; expires="+d.toUTCString();document.cookie=name+"="+value+expires+"; path=/"}document.addEventListener("DOMContentLoaded",function(){const buttons=document.querySelectorAll(".astroid-cookie-allow");if(!buttons||!buttons.length){return}Array.prototype.forEach.call(buttons,function(btn){btn.addEventListener("click",function(evt){evt.preventDefault();setCookie("astroid_cookie_"+TEMPLATE_HASH,"ok",2592e6);const consent=btn.closest&&btn.closest("#astroid-cookie-consent");if(consent){fadeOut(consent,200)}})})})})();